import React, { useState, useEffect } from "react";
import ab1 from "../assets/ab-hl-1.jpg";
import ab2 from "../assets/ab-hl-2.jpeg";
import ab3 from "../assets/ab-hl-3.jpg";
import ab4 from "../assets/ab-hl-4.jpg";

function Counter({ end, label, icon }) {
  const [count, setCount] = useState(0);

  useEffect(() => {
    let start = 0;
    const duration = 1400;
    const startTime = performance.now();

    const animate = (time) => {
      const progress = Math.min((time - startTime) / duration, 1);
      setCount(Math.floor(progress * end));
      if (progress < 1) requestAnimationFrame(animate);
    };

    requestAnimationFrame(animate);
  }, [end]);

  return (
    <div
      style={{
        flex: 1,
        minWidth: 160,
        padding: "18px 12px",
        borderRadius: "14px",
        background: "#f8fbff",
        boxShadow: "0 6px 18px rgba(0,0,0,0.08)",
        textAlign: "center",
        animation: "fadeUp 0.8s ease forwards",
      }}
    >
      <div style={{ fontSize: 28 }}>{icon}</div>
      <div style={{ fontSize: 26, fontWeight: 700, color: "#0e3b5f" }}>
        {count.toLocaleString()}+
      </div>
      <div style={{ fontSize: 14, color: "#555" }}>{label}</div>
    </div>
  );
}

function About() {
  const images = [ab1, ab2, ab3, ab4];
  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((p) => (p + 1) % images.length);
    }, 4000);
    return () => clearInterval(interval);
  }, []);

  return (
    <section
      id="about-section"
      style={{
        position: "relative",
        height: "520px",
        display: "flex",
        alignItems: "flex-end",
        justifyContent: "center",
        margin: "70px auto",
        borderRadius: "18px",
        overflow: "hidden",
        maxWidth: "1100px",
        boxShadow: "0 10px 28px rgba(0,0,0,0.25)",
      }}
    >
      {/* Background Slideshow */}
      <img
        src={images[currentIndex]}
        alt="About Slide"
        style={{
          position: "absolute",
          width: "100%",
          height: "100%",
          objectFit: "cover",
          top: 0,
          left: 0,
          zIndex: -1,
          transition: "opacity 1s ease-in-out",
        }}
      />

      {/* Info Box */}
      <div
        style={{
          width: "100%",
          padding: "30px",
          background: "rgba(255,255,255,0.9)",
          backdropFilter: "blur(6px)",
          textAlign: "center",
        }}
      >
        <h2
          style={{
            fontSize: 28,
            fontWeight: 700,
            color: "#007bff",
            marginBottom: 12,
          }}
        >
          HEALink
        </h2>

        <p
          style={{
            maxWidth: 900,
            margin: "0 auto 28px",
            fontSize: 16,
            lineHeight: 1.6,
            color: "#333",
          }}
        >
          HEALink was started with a vision to connect people with better
          healthcare solutions. We provide pathology, medicine, consultancy, and
          blood bank services to make healthcare accessible and reliable for
          everyone. Our mission is to ensure that every individual gets the care
          they need with trust and convenience.
        </p>

        {/* ===== Animated Stats (LIKE VIDEO) ===== */}
        <div
          style={{
            display: "flex",
            gap: 18,
            flexWrap: "wrap",
            justifyContent: "center",
            marginTop: 10,
          }}
        >
          <Counter end={120000} label="Platform Visits" icon="👀" />
          <Counter end={18000} label="Happy Users" icon="😊" />
          <Counter end={1200} label="Verified Doctors" icon="🩺" />
          <Counter end={45000} label="Orders Delivered" icon="📦" />
        </div>
      </div>

      {/* animation keyframes */}
      <style>
        {`
          @keyframes fadeUp {
            from {
              opacity: 0;
              transform: translateY(18px);
            }
            to {
              opacity: 1;
              transform: translateY(0);
            }
          }
        `}
      </style>
    </section>
  );
}

export default About;
